PS_CONTROL_SIGNALS.template:
// PS Control Signals: POR, mode, JTAG, init
PS_CONTROL_SIGNALS_inst (
  // Power-On Reset, mode pins
  .POR_OVERRIDE(por_override),      // in: override POR detection
  .PS_MODE(ps_mode),                // in[2:0]: boot mode selection
  .PS_POR_B(ps_por_b),              // in: power-on reset (active low)
  // JTAG chain
  .PS_JTAG_TCK(ps_jtag_tck),        // in: test clock
  .PS_JTAG_TDI(ps_jtag_tdi),        // in: test data in
  .PS_JTAG_TDO(ps_jtag_tdo),        // out: test data out
  .PS_JTAG_TMS(ps_jtag_tms),        // in: test mode select
  // Init / status
  .PS_INIT_B(ps_init_b),            // inout: init complete (open-drain)
  .PS_PROG_B(ps_prog_b),            // in: program enable
  .PS_DONE(ps_done),                // out: configuration done
  .PS_ERROR_OUT(ps_error_out),      // out: error indicator
  .PS_ERROR_STATUS(ps_error_status) // out: error status code
);

PS_GEM_MAC.template:
// PS Gigabit Ethernet MAC: EMIO data, DMA control
PS_GEM_MAC_inst (
  // RX data from PHY (via EMIO)
  .rx_w_data(rx_w_data),          // out[31:0]: receive data
  .rx_w_wr(rx_w_wr),              // out: receive write valid
  .rx_w_sop(rx_w_sop),            // out: start of packet
  .rx_w_eop(rx_w_eop),            // out: end of packet
  .rx_w_err(rx_w_err),            // out: error flag
  .rx_w_status(rx_w_status),      // out[44:0]: status / FCS
  .rx_w_flush(rx_w_flush),        // out: flush buffer
  .rx_w_overflow(rx_w_overflow),  // in: overflow condition
  // TX DMA handshake
  .dma_tx_end_tog(dma_tx_end_tog),       // out: TX DMA end toggle
  .dma_tx_status_tog(dma_tx_status_tog), // in: TX status toggle
  // TX status
  .tx_r_status(tx_r_status)               // out[3:0]: transmit status
);

PS_POWER.template:
// PS Power Supply pins: all supply rails
// GND, VCCINT, VCCAUX, VCCBRAM, VCCADC, VCCO_*, VCC_PS*
PS_POWER_inst (
  // Core supplies
  .GND(gnd),                         // supply: ground
  .VCCINT(vccint),                   // supply: core 0.9V
  .VCCAUX(vccaux),                   // supply: aux 1.8V
  .VCCBRAM(vccbram),                 // supply: BRAM 0.9V
  // I/O banks
  .VCCO_PSIO0(vcco_psio0),           // supply: I/O bank 0
  .VCCO_PSIO1(vcco_psio1),           // supply: I/O bank 1
  .VCCO_PSIO2(vcco_psio2),           // supply: I/O bank 2
  .VCCO_PSIO3(vcco_psio3),           // supply: I/O bank 3
  .VCCO_PSDDR(vcco_psddr),           // supply: DDR I/O
  // PS power domains
  .VCC_PSINTFP(vcc_psintfp),         // supply: full-power domain
  .VCC_PSINTLP(vcc_psintlp),         // supply: low-power domain
  .VCC_PSBATT(vcc_psbatt),           // supply: battery backup
  .VCC_PSPLL(vcc_pspll),             // supply: PLL
  // Transceiver / special supplies
  .PS_MGTRAVCC(ps_mgtravcc),         // supply: transceiver AVCC
  .PS_MGTRAVTT(ps_mgtravtt)          // supply: transceiver AVTT
);
